const body = $input.first().json.body || $input.first().json;

// Pegar field_id e novo valor
const fieldId = body.field_id || (body.history_items?.[0]?.field?.id) || '';
const newValue = body.history_items?.[0]?.after?.value || body.value || '';
const taskId = body.task_id || body.task?.id || '';

// Só processar se for o campo contrato_revisado_manual
const isOurField = fieldId === '37bf7603-08ed-4bed-bafd-75a828fa251f' || fieldId === '';

return [{ json: { prosseguir: isOurField && taskId !== '', taskId, newValue: String(newValue) } }];

const dados = $input.first().json;
const task = $('GET Task MF03').first().json;
const cf = task.custom_fields || [];

// Pegar valor atual do campo contrato_revisado_manual
const campoRevisado = cf.find(f => f.id === '37bf7603-08ed-4bed-bafd-75a828fa251f');
let estadoAtual = '';
if (campoRevisado) {
  if (campoRevisado.type_config?.options) {
    const opt = campoRevisado.type_config.options.find(o =>
      o.orderindex === campoRevisado.value || o.id === campoRevisado.value);
    estadoAtual = opt?.name || String(campoRevisado.value || '');
  } else {
    estadoAtual = String(campoRevisado.value || '');
  }
}
const estadoNorm = estadoAtual.toLowerCase().trim();

// Pegar pendências
const campoPend = cf.find(f => f.id === 'db59580c-c1be-45c9-8af6-ef0e25ad1cef');
const pendencias = campoPend?.value || 'não especificado';

const now = new Date();
const brt = new Date(now.getTime() - 3*3600000);
const dtBRT = brt.toLocaleString('pt-BR', {timeZone:'UTC'});

let acao = 'pendente';
let comentario = '';

if (estadoNorm.includes('validado')) {
  acao = 'validado';
  comentario = `✅ MF03 — CONFERÊNCIA VALIDADA
Data: ${dtBRT} (BRT)
—
Minuta aprovada pela equipe.
✅ Pronto para MF04 — Gerar PDF Final.
(Dispare MF04 manualmente ou via automação do ClickUp)`;
} else if (estadoNorm.includes('corrigir') || estadoNorm.includes('correc')) {
  acao = 'corrigir';
  comentario = `⚠️ MF03 — CORREÇÃO NECESSÁRIA
Data: ${dtBRT} (BRT)
—
Pendências: ${pendencias}
—
❌ MF04 bloqueado até nova validação.
Após corrigir a minuta, altere o campo para "Validado".`;
} else {
  acao = 'pendente';
  comentario = `⏳ MF03 — CONFERÊNCIA PENDENTE
Data: ${dtBRT} (BRT)
—
Aguardando revisão da equipe.`;
}

return [{ json: { taskId: task.id, taskName: task.name, acao, comentario, pendencias, dtBRT } }];

